// styles.js

import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  homeContainer: {
    position: 'relative',
    zIndex: 0,
  },
  heroImage: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
  },
  section: {
    textAlign: 'center',
  },
  imageContainer: {
    position: 'relative',
    marginBottom: theme.spacing(2),
    display: 'flex',
    flexDirection: 'column', // Ställ in flexriktningen till kolumn
  },
  overlappingImage: {
    marginTop: '-50%', // Höjden på den övre bilden
    marginLeft: '75%',
    width: '100%', // 50% större bredd för den undre bilden
    height: 'auto',
  },
  image: {
    width: '100%',
    height: 'auto',
    objectFit: 'cover',
    borderRadius: 0, // Inga rundade hörn
  },
  textContainer: {
    padding: theme.spacing(2),
  },
}));

export default useStyles;
